public int caughtSpeeding(int speed, boolean isBirthday) {
    int speedLimit = 60;

    if (isBirthday) {
        speedLimit += 5;
    }

    if (speed <= speedLimit) {
        return 0;
    } else if (speed >= speedLimit + 1 && speed <= speedLimit + 20) {
        return 1;
    } else {
        return 2;
    }
}

